  1	import React, { FC } from 'react';
  2	import { Trans } from 'react-i18next';
  3	
  4	import UserDefinedNetworkModel from '@kubevirt-ui/kubevirt-api/console/models/UserDefinedNetworkModel';
  5	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  6	import ExternalLink from '@kubevirt-utils/components/ExternalLink/ExternalLink';
  7	import { getConsoleVirtctlCommand } from '@kubevirt-utils/components/SSHAccess/utils';
  8	import { documentationURL } from '@kubevirt-utils/constants/documentation';
  9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 10	import {
 11	  ClusterUserDefinedNetworkModelGroupVersionKind,
 12	  UserDefinedNetworkModelGroupVersionKind,
 13	} from '@kubevirt-utils/models';
 14	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 15	import useNamespaceUDN from '@kubevirt-utils/resources/udn/hooks/useNamespaceUDN';
 16	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 17	import {
 18	  DescriptionListDescription,
 19	  DescriptionListGroup,
 20	  DescriptionListTerm,
 21	  Grid,
 22	  GridItem,
 23	  Popover,
 24	  Text,
 25	} from '@patternfly/react-core';
 26	import { HelpIcon } from '@patternfly/react-icons';
 27	
 28	import VirtctlSSHCommandClipboardCopy from './VirtctlSSHCommandClipboardCopy';
 29	
 30	import './ConsoleOverVirtctl.scss';
 31	
 32	type ConsoleOverVirtctlProps = {
 33	  vm: V1VirtualMachine;
 34	};
 35	
 36	const ConsoleOverVirtctl: FC<ConsoleOverVirtctlProps> = ({ vm }) => {
 37	  const { t } = useKubevirtTranslation();
 38	
 39	  const [isNamespaceManagedByUDN, udn] = useNamespaceUDN(getNamespace(vm));
 40	
 41	  return (
 42	    <DescriptionListGroup className="pf-v6-c-description-list__group">
 43	      <DescriptionListTerm className="pf-v6-u-font-size-xs">
 44	        <Text className="pf-v5-u-disabled-color-100">
 45	          {t('SSH using virtctl')}{' '}
 46	          <Popover
 47	            bodyContent={
 48	              <>
 49	                <Trans t={t}>
 50	                  <div>
 51	                    Open an SSH connection with the VM using the cluster API server. You must be
 52	                    able to access the API server and have virtctl command line tool installed.
 53	                  </div>
 54	                  <br />
 55	                  <div>
 56	                    For more details, see{' '}
 57	                    <ExternalLink href={documentationURL.VIRTCTL_CLI}>
 58	                      Installing virtctl
 59	                    </ExternalLink>{' '}
 60	                    in Getting started with OpenShift Virtualization.
 61	                  </div>
 62	                </Trans>
 63	                <br />
 64	                <Grid>
 65	                  <GridItem span={2}>{t('Example: ')}</GridItem>
 66	                  <GridItem id="ssh-using-virtctl--example" span={10}>
 67	                    {getConsoleVirtctlCommand(vm)}
 68	                  </GridItem>
 69	                </Grid>
 70	              </>
 71	            }
 72	            aria-label="Help"
 73	            className="virtctl-popover"
 74	            position="right"
 75	          >
 76	            <HelpIcon />
 77	          </Popover>
 78	        </Text>
 79	      </DescriptionListTerm>
 80	      <DescriptionListDescription className="pf-v6-c-description-list__description">
 81	        {isNamespaceManagedByUDN ? (
 82	          <>
 83	            {t("Virtctl is disabled for this namespace as it's managed by")}{' '}
 84	            <ResourceLink
 85	              groupVersionKind={
 86	                udn.kind === UserDefinedNetworkModel.kind
 87	                  ? UserDefinedNetworkModelGroupVersionKind
 88	                  : ClusterUserDefinedNetworkModelGroupVersionKind
 89	              }
 90	              inline
 91	              name={getName(udn)}
 92	              namespace={getNamespace(udn)}
 93	            />{' '}
 94	          </>
 95	        ) : (
 96	          <VirtctlSSHCommandClipboardCopy vm={vm} />
 97	        )}
 98	      </DescriptionListDescription>
 99	    </DescriptionListGroup>
100	  );
101	};
102	
103	export default ConsoleOverVirtctl;

